# Search CloudTrail for any root user activity in the last 90 days
aws cloudtrail lookup-events   --lookup-attributes AttributeKey=Username,AttributeValue=root   --query 'Events[].{Time:EventTime, Event:EventName, IP:CloudTrailEvent}'   --output table

# Create an EventBridge rule to alert on root logins:
aws events put-rule   --name root-user-login-alert   --event-pattern '{
    "source": ["aws.signin"],
    "detail-type": ["AWS Console Sign In via CloudTrail"],
    "detail": {
      "userIdentity": {
        "type": ["Root"]
      }
    }
  }'   --state ENABLED

{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "DenyRootAccessKeyCreation",
      "Effect": "Deny",
      "Action": [
        "iam:CreateAccessKey"
      ],
      "Resource": "*",
      "Condition": {
        "StringEquals": {
          "aws:PrincipalType": "Root"
        }
      }
    }
  ]
}
